// ==========================
// LOGIC SUMMARY / CHANGE NOTES
// ==========================
// Current behavior implemented after iterative tuning:
// 1. This function now has 4 outputs:
//    - output 1 -> DVCC charge current limit (A)
//    - output 2 -> ESS grid setpoint (W)
//    - output 3 -> VE.Bus AC input current limit (A)
//    - output 4 -> VRM notification message
// 2. The function accepts multiple message types:
//    - `topic = battery-voltage` -> updates battery voltage state
//    - `topic = grid-power` -> updates measured grid import power in W
//      (preferred source: GX System GRID CT sensor, e.g. `/Ac/Grid/L1/Power`)
//    - any other topic / inject -> recalculates outputs using stored state
// 3. Night charging uses hysteresis:
//    - ON again at 54.5V or lower
//    - OFF at 54.8V or higher
// 4. Morning charging uses hysteresis:
//    - ON below 53.5V
//    - OFF above 53.8V
// 5. Evening charging uses hysteresis:
//    - ON below 54.0V
//    - OFF above 54.4V
// 6. Base grid setpoint schedule:
//    - 2700W at night
//    - 1950W during the rest of the day
// 7. High-voltage protection for unknown external MPPT charging:
//    - start limiting when battery voltage rises above 55.0V
//    - release only after voltage drops back to 54.8V or lower
//    - taper grid setpoint smoothly down to a minimum of 200W by 55.2V
// 8. Hourly budget control:
//    - integrate positive grid import every hour in Wh
//    - intended to use the GX GRID CT sensor value as the power source
//    - day budget = 2000Wh / hour
//    - night budget = 2700Wh / hour
//    - allowed remaining average power is recalculated continuously
// 9. Final grid setpoint is the minimum of:
//    - base schedule
//    - high-voltage limit
//    - hourly budget limit
// 10. Hourly budget has higher priority than the 200W voltage minimum.
//     If the hour budget is exhausted, setpoint may drop below 200W.
// 11. Grid setpoint reduction due to battery over-voltage is smoothed so the battery does not
//     see large sudden load changes.
// 12. VE.Bus input current limit is now calculated dynamically together with grid setpoint:
//     - derived from final grid setpoint / grid voltage
//     - uses `flow.gridVoltage` if available, else defaults to 230V
//     - capped by safe limits: 12.6A at night, 9.6A during daytime
//     - if hourly capacity is exhausted or unknown, falls back to the safe limit for that period
// 13. A VRM notification is emitted when either:
//     - grid setpoint changes
//     - VE.Bus Input 1 current limit changes
// 14. `boostActive`, `activeWindow`, battery voltage, grid power, and hourly budget state are
//     all stored in context.
// 15. `day-night.txt` and the embedded `func` in `flows.json` must always stay synchronized.

// ==========================
// INPUT / OUTPUT TOPICS
// ==========================
const BATTERY_TOPIC = "battery-voltage";
const GRID_TOPIC = "grid-power";

// ==========================
// CONSTANTS
// ==========================
const MAX_CHARGE_CURRENT = 25;
const DEFAULT_GRID_VOLTAGE = 230;
const DAY_SAFE_INPUT_CURRENT_LIMIT = 9.6;
const NIGHT_SAFE_INPUT_CURRENT_LIMIT = 12.6;

const DAY_BASE_GRID_SETPOINT = 1950;
const NIGHT_BASE_GRID_SETPOINT = 2700;

const DAY_HOURLY_BUDGET_W = 2000;
const NIGHT_HOURLY_BUDGET_W = 2700;

const NIGHT_ON_VOLTAGE = 54.5;
const NIGHT_OFF_VOLTAGE = 54.8;

const MORNING_ON_VOLTAGE = 53.5;
const MORNING_OFF_VOLTAGE = 53.8;

const EVENING_ON_VOLTAGE = 54.0;
const EVENING_OFF_VOLTAGE = 54.4;

const HIGH_VOLTAGE_LIMIT_START = 55.0;
const HIGH_VOLTAGE_LIMIT_RELEASE = 54.8;
const HIGH_VOLTAGE_LIMIT_FULL = 55.2;
const MIN_GRID_SETPOINT = 200;
const MAX_GRID_STEP_W = 100;

// ==========================
// TIME
// ==========================
const now = new Date();
const hour = now.getHours();
const minute = now.getMinutes();
const second = now.getSeconds();

// ==========================
// CONTEXT MEMORY
// ==========================
let boostActive = context.get("boostActive") || false;
const previousWindow = context.get("activeWindow") || "none";
let batteryVoltage = Number(context.get("batteryVoltage"));
const rawStoredGridPower = context.get("gridPowerW");
const hasGridPowerReading = rawStoredGridPower !== undefined && rawStoredGridPower !== null && Number.isFinite(Number(rawStoredGridPower));
const storedGridPowerW = hasGridPowerReading ? Math.max(0, Number(rawStoredGridPower)) : 0;
let gridPowerW = storedGridPowerW;
let voltageLimitActive = context.get("voltageLimitActive") || false;
const previousGridSetpoint = Number(context.get("gridSetpoint"));
const previousAcInputCurrentLimit = Number(context.get("acInputCurrentLimit"));
let hourBudget = context.get("hourBudget") || {
    hourKey: "",
    lastTs: 0,
    usedWh: 0,
    startTs: 0
};

// ==========================
// HELPERS
// ==========================
function clamp(value, min, max) {
    return Math.min(Math.max(value, min), max);
}

function round1(value) {
    return Math.round(value * 10) / 10;
}

function getHourKey(date) {
    return [
        date.getFullYear(),
        String(date.getMonth() + 1).padStart(2, "0"),
        String(date.getDate()).padStart(2, "0")
    ].join("-") + " " + String(date.getHours()).padStart(2, "0");
}

function getHourStartTs(date) {
    return new Date(
        date.getFullYear(),
        date.getMonth(),
        date.getDate(),
        date.getHours(),
        0,
        0,
        0
    ).getTime();
}

function formatTime(date) {
    return `${String(date.getHours()).padStart(2, "0")}:${String(date.getMinutes()).padStart(2, "0")}`;
}

function advanceHourBudget(state, date, importPowerW) {
    const nextState = {
        hourKey: state.hourKey || "",
        lastTs: Number(state.lastTs) || 0,
        usedWh: Number(state.usedWh) || 0,
        startTs: Number(state.startTs) || 0
    };

    const nowTs = date.getTime();
    const hourKey = getHourKey(date);
    const hourStartTs = getHourStartTs(date);

    if (!nextState.lastTs || nextState.hourKey !== hourKey || nextState.lastTs < hourStartTs) {
        nextState.hourKey = hourKey;
        nextState.lastTs = hourStartTs;
        nextState.usedWh = 0;
        nextState.startTs = 0;
    }

    if (nowTs > nextState.lastTs) {
        const deltaHours = (nowTs - nextState.lastTs) / 3600000;

        if (Math.max(0, importPowerW) > 0 && !nextState.startTs) {
            nextState.startTs = nextState.lastTs;
        }

        nextState.usedWh += Math.max(0, importPowerW) * deltaHours;
        nextState.lastTs = nowTs;
    }

    return nextState;
}

function smoothReduction(previousValue, targetValue, maxStep) {
    if (!Number.isFinite(previousValue)) {
        return targetValue;
    }

    if (targetValue < previousValue - maxStep) {
        return previousValue - maxStep;
    }

    if (targetValue > previousValue + maxStep) {
        return previousValue + maxStep;
    }

    return targetValue;
}

function buildNotification(window, gridSetpoint, acInputCurrentLimit) {
    const parts = [
        `${window}`,
        `V=${batteryVoltage.toFixed(2)}V`,
        `Grid setpoint=${gridSetpoint}W`,
        `Input 1 current=${acInputCurrentLimit}A`
    ];

    if (limitFlags.length > 0) {
        parts.push(`Limit=${limitFlags.join("+")}`);
    }

    return {
        topic: "vrm-notification",
        payload: parts.join(" | "),
        notification: {
            message: parts.join(" | "),
            level: "info",
            timestamp: now.toISOString()
        }
    };
}

function buildOutputs(chargeCurrent, gridSetpoint, safeInputCurrentLimit, useSafeFallbackInputLimit) {
    const gridVoltage = Number(flow.get("gridVoltage")) || DEFAULT_GRID_VOLTAGE;
    const derivedInputCurrentLimit = gridSetpoint > 0
        ? round1(gridSetpoint / gridVoltage)
        : 0;
    const acInputCurrentLimit = useSafeFallbackInputLimit
        ? safeInputCurrentLimit
        : Math.min(safeInputCurrentLimit, derivedInputCurrentLimit);

    const notifyMsg =
        gridSetpoint !== previousGridSetpoint ||
        acInputCurrentLimit !== previousAcInputCurrentLimit
            ? buildNotification(windowName, gridSetpoint, acInputCurrentLimit)
            : null;

    context.set("acInputCurrentLimit", acInputCurrentLimit);

    return [
        {
            topic: "charge-current-limit",
            payload: chargeCurrent
        },
        {
            topic: "grid-setpoint",
            payload: gridSetpoint
        },
        {
            topic: "ac-input-current-limit",
            payload: acInputCurrentLimit
        },
        notifyMsg
    ];
}

// ==========================
// UPDATE STORED INPUTS
// ==========================
hourBudget = advanceHourBudget(hourBudget, now, storedGridPowerW);

if (msg.topic === BATTERY_TOPIC) {
    const incomingVoltage = Number(msg.payload);

    if (Number.isFinite(incomingVoltage)) {
        batteryVoltage = incomingVoltage;
        context.set("batteryVoltage", batteryVoltage);
    }
}
else if (msg.topic === GRID_TOPIC) {
    const incomingGridPower = Number(msg.payload);

    if (Number.isFinite(incomingGridPower)) {
        gridPowerW = Math.max(0, incomingGridPower);
        context.set("gridPowerW", gridPowerW);
    }
}

context.set("hourBudget", hourBudget);

if (!Number.isFinite(batteryVoltage)) {
    node.status({
        fill: "grey",
        shape: "ring",
        text: "WAITING FOR BATTERY VOLTAGE"
    });
    return null;
}

// ==========================
// TIME WINDOWS
// ==========================
const nightWindow = (hour >= 22 || hour < 6);

const morningWindow =
    (hour > 6 && hour < 11) ||
    (hour === 6) ||
    (hour === 11 && minute <= 59);

const eveningWindow = hour >= 17;

const baseScheduleSetpoint = nightWindow ? NIGHT_BASE_GRID_SETPOINT : DAY_BASE_GRID_SETPOINT;
const hourlyBudgetLimit = nightWindow ? NIGHT_HOURLY_BUDGET_W : DAY_HOURLY_BUDGET_W;

// ==========================
// CHARGE CURRENT WINDOW LOGIC
// ==========================
let windowName = "OUTSIDE";
let baseChargeCurrent = 0;

if (nightWindow) {
    windowName = "NIGHT";

    if (previousWindow !== windowName) {
        boostActive = true;
    }

    if (boostActive && batteryVoltage >= NIGHT_OFF_VOLTAGE) {
        boostActive = false;
    }

    if (!boostActive && batteryVoltage <= NIGHT_ON_VOLTAGE) {
        boostActive = true;
    }

    baseChargeCurrent = boostActive ? MAX_CHARGE_CURRENT : 0;
}
else if (morningWindow) {
    windowName = "MORNING";

    if (previousWindow !== windowName) {
        boostActive = false;
    }

    if (!boostActive && batteryVoltage < MORNING_ON_VOLTAGE) {
        boostActive = true;
    }

    if (boostActive && batteryVoltage > MORNING_OFF_VOLTAGE) {
        boostActive = false;
    }

    baseChargeCurrent = boostActive ? MAX_CHARGE_CURRENT : 0;
}
else if (eveningWindow) {
    windowName = "EVENING";

    if (previousWindow !== windowName) {
        boostActive = false;
    }

    if (!boostActive && batteryVoltage < EVENING_ON_VOLTAGE) {
        boostActive = true;
    }

    if (boostActive && batteryVoltage > EVENING_OFF_VOLTAGE) {
        boostActive = false;
    }

    baseChargeCurrent = boostActive ? MAX_CHARGE_CURRENT : 0;
}
else {
    boostActive = false;
    baseChargeCurrent = 0;
}

// ==========================
// HIGH-VOLTAGE GRID SETPOINT LIMIT
// ==========================
if (!voltageLimitActive && batteryVoltage > HIGH_VOLTAGE_LIMIT_START) {
    voltageLimitActive = true;
}

if (voltageLimitActive && batteryVoltage <= HIGH_VOLTAGE_LIMIT_RELEASE) {
    voltageLimitActive = false;
}

let voltageLimitedSetpoint = baseScheduleSetpoint;

if (voltageLimitActive) {
    const taper = clamp(
        (HIGH_VOLTAGE_LIMIT_FULL - batteryVoltage) /
        (HIGH_VOLTAGE_LIMIT_FULL - HIGH_VOLTAGE_LIMIT_START),
        0,
        1
    );

    voltageLimitedSetpoint = Math.round(
        MIN_GRID_SETPOINT + (baseScheduleSetpoint - MIN_GRID_SETPOINT) * taper
    );
}

// Apply smoothing only to the voltage-based reduction so the battery does not see large jumps.
if (voltageLimitActive) {
    voltageLimitedSetpoint = Math.round(
        smoothReduction(
            previousGridSetpoint,
            voltageLimitedSetpoint,
            MAX_GRID_STEP_W
        )
    );
}

// ==========================
// HOURLY GRID BUDGET LIMIT
// ==========================
const secondsIntoHour = minute * 60 + second;
const secondsLeftInHour = Math.max(1, 3600 - secondsIntoHour);
const hoursLeftInHour = secondsLeftInHour / 3600;
const usedWh = hourBudget.usedWh || 0;
const hourStartTs = getHourStartTs(now);
const hourEndLabel = formatTime(new Date(hourStartTs + 3600000));
const accumulationStartLabel = hourBudget.startTs > 0
    ? formatTime(new Date(hourBudget.startTs))
    : formatTime(new Date(hourStartTs));
const remainingWh = clamp(hourlyBudgetLimit - usedWh, 0, hourlyBudgetLimit);
const budgetLimitedSetpoint = Math.round(remainingWh / hoursLeftInHour);
const safeInputCurrentLimit = nightWindow ? NIGHT_SAFE_INPUT_CURRENT_LIMIT : DAY_SAFE_INPUT_CURRENT_LIMIT;
const useSafeFallbackInputLimit = remainingWh <= 0 || !hasGridPowerReading;

// ==========================
// FINAL OUTPUTS
// ==========================
const finalGridSetpoint = Math.max(
    0,
    Math.round(
        Math.min(
            baseScheduleSetpoint,
            voltageLimitedSetpoint,
            budgetLimitedSetpoint
        )
    )
);

const currentRatio = baseScheduleSetpoint > 0
    ? clamp(finalGridSetpoint / baseScheduleSetpoint, 0, 1)
    : 0;

const finalChargeCurrent = baseChargeCurrent > 0
    ? round1(baseChargeCurrent * currentRatio)
    : 0;

context.set("boostActive", boostActive);
context.set("activeWindow", windowName);
context.set("voltageLimitActive", voltageLimitActive);
context.set("gridSetpoint", finalGridSetpoint);

// ==========================
// STATUS
// ==========================
const limitFlags = [];

if (voltageLimitActive && finalGridSetpoint <= voltageLimitedSetpoint) {
    limitFlags.push("HV");
}

if (budgetLimitedSetpoint < Math.min(baseScheduleSetpoint, voltageLimitedSetpoint)) {
    limitFlags.push("HOUR");
}

let fill = "grey";

if (windowName === "NIGHT") {
    fill = finalChargeCurrent > 0 ? "blue" : "yellow";
}
else if (windowName === "MORNING" || windowName === "EVENING") {
    fill = finalChargeCurrent > 0 ? "green" : "yellow";
}

const flagsText = limitFlags.length > 0 ? ` | ${limitFlags.join("+")}` : "";

node.status({
    fill,
    shape: finalChargeCurrent > 0 || finalGridSetpoint > 0 ? "dot" : "ring",
    text: `${windowName} | V=${batteryVoltage.toFixed(2)}V | ${finalChargeCurrent}A | ${finalGridSetpoint}W | ${accumulationStartLabel}-${hourEndLabel} ${Math.round(usedWh)}Wh${flagsText}`
});

return buildOutputs(
    finalChargeCurrent,
    finalGridSetpoint,
    safeInputCurrentLimit,
    useSafeFallbackInputLimit
);

const defaultTitle = "Day / Night Grid Control";

function normalizeType(value) {
    if (value === 0 || value === "0" || value === "warning") {
        return 0;
    }

    if (value === 1 || value === "1" || value === "alarm") {
        return 1;
    }

    return 2;
}

const title = msg.title || (msg.notification && msg.notification.title) || defaultTitle;
const rawType = msg.type !== undefined
    ? msg.type
    : (msg.notification && (msg.notification.type !== undefined ? msg.notification.type : msg.notification.level));
const rawMessage = (msg.notification && msg.notification.message) || msg.payload;

if (rawMessage === undefined || rawMessage === null || rawMessage === "") {
    return null;
}

const safeTitle = String(title)
    .replace(/\t/g, " ")
    .replace(/[\r\n]/g, " ")
    .trim()
    .slice(0, 100);

const safeMessage = String(rawMessage)
    .replace(/\t/g, " ")
    .replace(/[\r\n]/g, " ")
    .trim()
    .slice(0, 500);

msg.payload = `${normalizeType(rawType)}\t${safeTitle}\t${safeMessage}`;
return msg;

function localDayKey(date) {
    return [
        date.getFullYear(),
        String(date.getMonth() + 1).padStart(2, '0'),
        String(date.getDate()).padStart(2, '0')
    ].join('-');
}

const result = msg.payload && msg.payload.result;
if (!result || typeof result !== 'object') {
    node.status({ fill: 'red', shape: 'ring', text: 'no forecast data' });
    return null;
}

const shadeByHour = {
    5: 0.02,
    6: 0.04,
    7: 0.06,
    8: 0.10,
    9: 0.18,
    10: 0.30,
    11: 0.55,
    12: 0.72,
    13: 0.78,
    14: 0.62,
    15: 0.50,
    16: 0.42,
    17: 0.32,
    18: 0.22,
    19: 0.14,
    20: 0.08,
    21: 0.03
};

const hourlyCapW = {
    5: 20,
    6: 40,
    7: 80,
    8: 150,
    9: 300,
    10: 550,
    11: 1100,
    12: 1500,
    13: 1500,
    14: 1200,
    15: 800,
    16: 700,
    17: 500,
    18: 320,
    19: 220,
    20: 140,
    21: 40
};

const historicalReference = {
    sunnyPeakKW: '1.4-1.5',
    cloudyPeakKW: '<1.0',
    dominantWindow: '11:00-17:00',
    extendedWindow: '05:00-21:00'
};

const resolution = Number(msg.resolution) || 1;
const periodHours = resolution > 0 ? 1 / resolution : 1;
const adjustedResult = {};
const summaryByDay = {};

for (const [key, rawValue] of Object.entries(result)) {
    const date = new Date(key);
    const hour = date.getHours();
    const factor = shadeByHour[hour] || 0;
    const shadedW = factor > 0 ? Math.round(Math.max(0, Number(rawValue) || 0) * factor) : 0;
    const capW = hourlyCapW[hour] || 0;
    const adjustedW = capW > 0 ? Math.min(shadedW, capW) : 0;
    const dayKey = localDayKey(date);

    adjustedResult[key] = adjustedW;

    if (!summaryByDay[dayKey]) {
        summaryByDay[dayKey] = {
            energyWh: 0,
            peakW: 0,
            activeHours: 0
        };
    }

    summaryByDay[dayKey].energyWh += adjustedW * periodHours;
    summaryByDay[dayKey].peakW = Math.max(summaryByDay[dayKey].peakW, adjustedW);
    if (adjustedW > 0) {
        summaryByDay[dayKey].activeHours += periodHours;
    }
}

const todayKey = localDayKey(new Date());
const today = summaryByDay[todayKey] || { energyWh: 0, peakW: 0, activeHours: 0 };
const todayKWh = +(today.energyWh / 1000).toFixed(2);
const todayPeakKW = +(today.peakW / 1000).toFixed(2);
const condition = todayPeakKW >= 1.0 ? 'sunny' : (todayKWh >= 2 ? 'cloudy' : 'low');

msg.topic = 'solar-forecast-adjusted';
msg.payload = {
    source: 'forecast.solar',
    location: 'Hokksund, Norway',
    activeWindow: '05:00-21:00',
    dominantWindow: '11:00-17:00',
    shading: 'trees / heavy shadow',
    rawResult: result,
    adjustedResult,
    summaryByDay,
    today: {
        energyWh: Math.round(today.energyWh),
        energyKWh: todayKWh,
        peakW: today.peakW,
        peakKW: todayPeakKW,
        activeHours: +today.activeHours.toFixed(2),
        condition
    },
    assumptions: {
        sunnyRangeKWh: '3-5',
        cloudyKWh: '2',
        shadeByHour,
        hourlyCapW,
        historicalReference
    }
};

node.status({ fill: 'blue', shape: 'dot', text: `${condition} | ${todayKWh}kWh | peak ${todayPeakKW}kW` });
return msg;

const data = msg.payload || {};
const today = data.today || { energyKWh: 0, peakKW: 0, condition: 'unknown' };
const summary = {
    updatedAt: new Date().toISOString(),
    source: data.source || 'forecast.solar',
    location: data.location || 'Hokksund, Norway',
    activeWindow: data.activeWindow || '11:00-17:00',
    condition: today.condition || 'unknown',
    energyWh: Number(today.energyWh) || 0,
    energyKWh: Number(today.energyKWh) || 0,
    peakW: Number(today.peakW) || 0,
    peakKW: Number(today.peakKW) || 0,
    activeHours: Number(today.activeHours) || 0
};

flow.set('solarForecastAdjusted', data);
flow.set('solarForecastToday', summary);

node.status({
    fill: summary.energyKWh > 0 ? 'green' : 'yellow',
    shape: 'dot',
    text: `${summary.condition} | ${summary.energyKWh.toFixed(2)}kWh | ${summary.activeWindow}`
});

msg.topic = 'solar-forecast-today';
msg.payload = summary;
return msg;
